using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-002", 3, 4.50m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-001", 2, 9.99m);
    }

    [TestMethod]
    public void AddItem_ReflectedInTotal()
    {
        _cart.AddItem("SKU-001", 2, 5.00m);

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleItems_ReflectedInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalIsZero()
    {
        _cart.AddItem("SKU-001", 1, 15.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);

        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    public void RemoveItem_EmptyCart_DoesNotThrow()
    {
        _cart.RemoveItem("SKU-001");
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        _cart.AddItem("SKU-001", 4, 2.50m);

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("SKU-001", 1, 20.00m);
        _cart.AddItem("SKU-002", 2, 15.00m);
        _cart.AddItem("SKU-003", 3, 5.00m);

        Assert.AreEqual(65.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.AddItem("SKU-002", 1, 50.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_TotalUnchanged()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        try
        {
            _cart.ApplyCoupon("BOGUS");
        }
        catch
        {
            // Implementation may throw for invalid codes; that's acceptable.
        }

        // If no exception was thrown, the total should remain unchanged.
        Assert.AreEqual(100.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverNegative()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m,
            "Total should never be negative after applying a coupon.");
    }

    // ── End-to-end workflow ────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("SKU-A", 2, 25.00m);
        _cart.AddItem("SKU-B", 1, 50.00m);
        _cart.RemoveItem("SKU-B");
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total >= 0m, "Total should be non-negative.");
        Assert.IsTrue(total <= 50.00m, "Total should not exceed pre-coupon amount.");
    }
}

